    48  void PassRegistry::registerPass(const PassInfo &PI, bool ShouldFree) {
    49    sys::SmartScopedWriter<true> Guard(Lock);
    50    bool Inserted =
    51        PassInfoMap.insert(std::make_pair(PI.getTypeInfo(), &PI)).second;
    52    assert(Inserted && "Pass registered multiple times!");
    53    (void)Inserted;
    54    PassInfoStringMap[PI.getPassArgument()] = &PI;
    55
    56    // Notify any listeners.
    57    for (auto *Listener : Listeners)
    58      Listener->passRegistered(&PI);
    59
    60    if (ShouldFree)
    61      ToFree.push_back(std::unique_ptr<const PassInfo>(&PI));
    62  }
    63
    64  void PassRegistry::enumerateWith(PassRegistrationListener *L) {
    65    sys::SmartScopedReader<true> Guard(Lock);
    66    for (auto PassInfoPair : PassInfoMap)
    67      L->passEnumerate(PassInfoPair.second);
    68  }
    69
    70  void PassRegistry::addRegistrationListener(PassRegistrationListener *L) {
    71    sys::SmartScopedWriter<true> Guard(Lock);
    72    Listeners.push_back(L);
    73  }
    74
    75  void PassRegistry::removeRegistrationListener(PassRegistrationListener *L) {
    76    sys::SmartScopedWriter<true> Guard(Lock);
    77
    78    auto I = llvm::find(Listeners, L);
    79    Listeners.erase(I);
    80  }

